@Component
class PaymentCompletedConsumer(
    private val objectMapper: ObjectMapper,
    private val accountService: AccountService,
) {
    private val log = LoggerFactory.getLogger(javaClass)

    @KafkaListener(
        topics = ["\${kafka.topics.payment-completed}"],
        groupId = "\${kafka.consumer.group-id}",
        containerFactory = "kafkaListenerContainerFactory",
    )
    fun handle(record: ConsumerRecord<String, String>) {
        val event = objectMapper.readValue<PaymentCompletedEvent>(record.value())
        MDC.put("correlationId", event.correlationId)
        MDC.put("paymentId", event.paymentId)
        try {
            log.info("Processing payment-completed event")
            runBlocking { accountService.updateBalance(event.accountId, event.amount) }
            log.info("Successfully processed payment-completed event")
        } finally {
            MDC.clear()
        }
    }
}
```

**`KafkaConsumerConfig.kt`** — config with error handling + retry:

```kotlin
@Configuration
@EnableKafka
class KafkaConsumerConfig(
    @Value("\${kafka.bootstrap-servers}") private val bootstrapServers: String,
    @Value("\${kafka.consumer.group-id}") private val groupId: String,
) {
    @Bean
    fun consumerFactory(): ConsumerFactory<String, String> {
        val props = mapOf(
            ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG to bootstrapServers,
            ConsumerConfig.GROUP_ID_CONFIG to groupId,
            ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG to StringDeserializer::class.java,
            ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG to StringDeserializer::class.java,
            ConsumerConfig.AUTO_OFFSET_RESET_CONFIG to "earliest",
            ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG to false,
        )
        return DefaultKafkaConsumerFactory(props)
    }

    @Bean
    fun kafkaListenerContainerFactory(): ConcurrentKafkaListenerContainerFactory<String, String> {
        val factory = ConcurrentKafkaListenerContainerFactory<String, String>()
        factory.consumerFactory = consumerFactory()
        factory.containerProperties.ackMode = ContainerProperties.AckMode.RECORD
        factory.setCommonErrorHandler(
            DefaultErrorHandler(FixedBackOff(1000L, 3L))
        )
        return factory
    }
}
```

