    @Autowired
    private lateinit var objectMapper: ObjectMapper

    @Autowired
    private lateinit var accountService: AccountService

    private lateinit var producer: KafkaTemplate<String, String>

    @BeforeEach
    fun setUp() {
        val props = KafkaTestUtils.producerProps(embeddedKafka)
        val pf = DefaultKafkaProducerFactory<String, String>(props)
        producer = KafkaTemplate(pf)
    }

    @Test
    fun `processes payment-completed event and updates balance`() {
        val event = PaymentCompletedEvent(
            paymentId = "pay_123",
            accountId = "acc_456",
            amount = BigDecimal("100.00"),
            currency = "USD",
            completedAt = Instant.now(),
            correlationId = "corr_789",
        )

        producer.send("payment.completed", event.paymentId, objectMapper.writeValueAsString(event))

        // assert balance updated — poll to account for async processing
        await().atMost(Duration.ofSeconds(5)).untilAsserted {
            val balance = runBlocking { accountService.getBalance("acc_456") }
            assertThat(balance).isEqualByComparingTo(BigDecimal("100.00"))
        }
    }
}
```

Key decisions:
- **Manual ack** (`AckMode.RECORD`) — no silent message loss on failures
- **`FixedBackOff(1000L, 3L)`** — retries 3x with 1s delay, then sends to error handler (add a DLT if you want dead-letter)
- **String deserializer** — deserialize in code so you control error handling vs schema-level failures
- **MDC for correlation IDs** — propagates through structured logging automatically
- **`runBlocking`** in the listener bridges to your coroutine-based `AccountService`

